"""CRUD routes — generated by doql."""
from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from database import get_db
import models
import schemas

router = APIRouter(prefix='/api/v1')

# ── Todo ──

@router.get("/todos", response_model=list[schemas.TodoResponse])
def list_todos(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):
    return db.query(models.Todo).offset(skip).limit(limit).all()

@router.get("/todos/{item_id}", response_model=schemas.TodoResponse)
def get_todo(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Todo).filter(models.Todo.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Todo not found")
    return obj

@router.post("/todos", response_model=schemas.TodoResponse, status_code=201)
def create_todo(data: schemas.TodoCreate, db: Session = Depends(get_db)):
    import uuid as _uuid
    payload = data.model_dump()
    payload.setdefault('id', str(_uuid.uuid4()))
    obj = models.Todo(**payload)
    db.add(obj)
    db.commit()
    db.refresh(obj)
    return obj

@router.patch("/todos/{item_id}", response_model=schemas.TodoResponse)
def update_todo(item_id: str, data: schemas.TodoUpdate, db: Session = Depends(get_db)):
    obj = db.query(models.Todo).filter(models.Todo.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Todo not found")
    for key, val in data.model_dump(exclude_unset=True).items():
        setattr(obj, key, val)
    db.commit()
    db.refresh(obj)
    return obj

@router.delete("/todos/{item_id}", status_code=204)
def delete_todo(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Todo).filter(models.Todo.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Todo not found")
    db.delete(obj)
    db.commit()
